mapper.select:
SELECT DISTINCT A.orderSeq, B.statusName, A.receiveName, A.amount, TO_CHAR(A.orderDate,'YYYY-MM-DD') AS orderDate, A.addr1, A.addr2, A.deliveryMemo, A.payType FROM `order` A INNER JOIN orderStatus B ON A.statusCode = B.statusCode WHERE A.userId = #{userId}
AND A.statusCode IN ('IN_DELIVERY','WAIT_DELIVERY','WAIT_PAY')
ORDER BY A.orderSeq DESC LIMIT #{offset} , #{limit}

SELECT A.orderSeq, B.productSeq, B.productName, B.imageURL, A.price, A.count, A.unitPrice FROM orderDetail A INNER JOIN product B ON A.productSeq = B.productSeq WHERE A.orderSeq IN
#{seq}
ORDER BY A.orderSeq DESC

mapper.update:
UPDATE `order`
SET statusCode = 'CANCEL'
WHERE
    userId = #{userId}
    AND orderSeq = #{orderSeq}
    AND statusCode IN('WAIT_DELIVERY','WAIT_PAY')

mapper.select:
SELECT
    COUNT(*)
FROM `order`
WHERE userId = #{userId}
AND statusCode = 'DONE_DELIVERY';
